//vip.opstream15.com/share/479065c78e0ba7c787a6cf9bcbc8c181","link_m3u8":"https://vip.opstream15.com/20220609/19817_d5f6c559/index.m3u8"}]}],"time":"46phút/tập","description":"<p>“Giới văn phòng hoa lệ” chú trọng những cảnh ngộ, sự xung đột và lựa chọn của các nhân vật thuộc các tầng lớp khác nhau trong văn phòng làm việc. Phim hướng đến việc thể hiện một cuộc chiến sinh tồn chân thực và hấp dẫn giữa những người làm việc ở môi trường công sở, đồng thời cổ vũ cho sự sáng tạo, trung thực và tận tâm của những người trẻ tuổi hiện nay. Chàng trai ngốc nghếch Lý Tưởng (Trương Hàn)sau khi tốt nghiệp Đại học một thân một mình bám trụ lại thành phố lớn. Anh ấy mơ ước trở thành quản lý cấp cao trong công ty và kiếm được thật nhiều tiền, tìm được một mỹ nhân để thành gia lập nghiệp. Không hiểu sao Lý Tưởng ưng tuyển vào công ty quảng cáo L&amp;L và anh được nhận làm trợ lý cho tổng giám đốc Trương Uy (Choo Ja Hyun). Trương Uy là một người phụ nữ thành công trong sự nghiệp nhưng lại gắp thất bại trong tình cảm. Cô tự mình gánh vác trách nhiệm trong công ty. Công ty gặp khó khăn và phải giảm biên chế. Ông trời run rủi thế nào khiến Lý Tưởng như có quý nhân phù trợ, gặp nạn hóa may, anh ấy âm thầm giúp Trương Uy vượt qua khó khăn.</p>","tmdb":{"type":"tv","id":"104171","season":1,"vote_average":7,"vote_count":1},"modified":"2023-06-23T19:32:35.000Z","_image_preserved":true},{"id":"625a892cb89b507b80d92b10","_id":"625a892cb89b507b80d92b10","title":"Thượng Hải, Vinh Hoa Lạc Lối","origin_name":"Shanghai Pioneering Story","slug":"thuong-hai-vinh-hoa-lac-loi","year":2018,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Thuyết Minh","episode_current":"Hoàn Tất (48/48)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Thuyết Minh